package org.apache.commons.lang3;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.lang3.steps",
    plugin = {"pretty", "html:target/cucumber-reports"}
)
public class CucumberTest {
}

package org.apache.commons.lang3.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;
import org.apache.commons.lang3.StringUtils;

public class StepDefs {

    private String testString;
    private boolean result;
    private String[] searchChars;
    private char[] searchCharArr;

    @Given("a string containing supplementary character U+20000 (\\uD840\\uDC00)")
    public void a_string_containing_supplementary_character_U20000() {
        testString = "\uD840\uDC00"; // This represents the supplementary character U+20000
    }

    @Given("a string containing supplementary characters U+20000 followed by U+20001 (\\uD840\\uDC00\\uD840\\uDC01)")
    public void a_string_containing_supplementary_characters_U20000_followed_by_U20001() {
        testString = "\uD840\uDC00\uD840\uDC01";
    }

    @When("checking if it contains the supplementary character U+20000")
    public void checking_if_it_contains_the_supplementary_character_U20000() {
        try {
            // Note: StringUtils.containsNone expects a string, not individual chars
            // We need to check if the test string contains none of the characters in the search
            String searchStr = "\uD840\uDC00"; // U+20000
            result = StringUtils.containsNone(testString, searchStr);
        } catch (Exception e) {
            // Handle any exception if needed
            result = false;
        }
    }

    @When("checking if it contains a different supplementary character U+20001 (\\uD840\\uDC01)")
    public void checking_if_it_contains_a_different_supplementary_character_U20001() {
        try {
            String searchStr = "\uD840\uDC01"; // U+20001
            result = StringUtils.containsNone(testString, searchStr);
        } catch (Exception e) {
            result = false;
        }
    }

    @When("checking if it contains any of the characters in array ['\\\\uD840', '\\\\uDC00'] (surrogate pair components)")
    public void checking_if_it_contains_any_of_the_characters_in_array_surrogate_pair_components() {
        try {
            searchCharArr = new char[] {'\uD840', '\uDC00'};
            result = StringUtils.containsNone(testString, searchCharArr);
        } catch (Exception e) {
            result = false;
        }
    }

    @Then("the method should return false because the string does contain the character")
    public void the_method_should_return_false_because_the_string_does_contain_the_character() {
        assertFalse("StringUtils.containsNone should return false as the string does contain the character", result);
    }

    @Then("the method should return true because the string does not contain the different character")
    public void the_method_should_return_true_because_the_string_does_not_contain_the_different_character() {
        assertTrue("StringUtils.containsNone should return true as the string does not contain the different character", result);
    }

    @Then("the method should return false because the string does contain the different supplementary character")
    public void the_method_should_return_false_because_the_string_does_contain_the_different_supplementary_character() {
        assertFalse("StringUtils.containsNone should return false as the string does contain the character", result);
    }
}

